     8→/// <summary>
     9→/// Represents a financial payment transaction in the system.
    10→/// Tracks the full lifecycle from creation through settlement or failure.
    11→/// </summary>
    12→public class Payment : IAggregateRoot
    13→{
    14→    private readonly List<IDomainEvent> _domainEvents = new();
    15→
    16→    /// <summary>
    17→    /// Gets the unique identifier for this payment.
    18→    /// </summary>
    19→    public Guid Id { get; private set; }
    20→
    21→    /// <summary>
    22→    /// Gets the timestamp when this payment was created.
    23→    /// </summary>
    24→    public DateTime CreatedAt { get; private set; }
    25→
    26→    /// <summary>
    27→    /// Gets the timestamp when this payment was last modified.
    28→    /// </summary>
    29→    public DateTime? UpdatedAt { get; private set; }
    30→
    31→    /// <summary>
    32→    /// Gets the monetary amount and currency for this payment.
    33→    /// </summary>
    34→    public Money Amount { get; private set; } = null!;
    35→
    36→    /// <summary>
    37→    /// Gets the current status of this payment.
    38→    /// </summary>
    39→    public PaymentStatus Status { get; private set; }
    40→
    41→    /// <summary>
    42→    /// Gets the ID of the user who initiated this payment.
    43→    /// </summary>
    44→    public Guid UserId { get; private set; }
    45→
    46→    /// <summary>
    47→    /// Gets the external transaction reference from the payment gateway.
    48→    /// </summary>
    49→    public string? GatewayTransactionId { get; private set; }
    50→
    51→    /// <summary>
    52→    /// Gets the error message if the payment failed.
    53→    /// </summary>
    54→    public string? FailureReason { get; private set; }
    55→
    56→    /// <summary>
    57→    /// Gets the number of retry attempts made for this payment.
    58→    /// </summary>
    59→    public int RetryCount { get; private set; }
    60→
    61→    /// <summary>
    62→    /// Gets the collection of domain events raised by this aggregate.
    63→    /// </summary>
    64→    public IReadOnlyCollection<IDomainEvent> DomainEvents => _domainEvents.AsReadOnly();
    65→
    66→    /// <summary>
    67→    /// Creates a new pending payment for the specified user and amount.
    68→    /// </summary>
    69→    public static Payment Create(Guid userId, Money amount)
    70→    {
    71→        return new Payment
    72→        {
    73→            Id = Guid.NewGuid(),
    74→            UserId = userId,
    75→            Amount = amount,
    76→            Status = PaymentStatus.Pending,
    77→            RetryCount = 0,
    78→            CreatedAt = DateTime.UtcNow
    79→        };
    80→    }
    81→
    82→    /// <summary>
    83→    /// Marks this payment as successfully processed.
    84→    /// Raises a PaymentProcessedEvent for downstream handlers.
    85→    /// </summary>
    86→    public void MarkAsProcessed(string gatewayTransactionId)
    87→    {
    88→        Status = PaymentStatus.Completed;
    89→        GatewayTransactionId = gatewayTransactionId;
    90→        UpdatedAt = DateTime.UtcNow;
    91→
    92→        _domainEvents.Add(new PaymentProcessedEvent(Id, UserId, Amount.Amount, Amount.Currency));
    93→    }
    94→
    95→    /// <summary>
    96→    /// Marks this payment as failed with the given reason.
    97→    /// </summary>
    98→    public void MarkAsFailed(string reason)
    99→    {
   100→        Status = PaymentStatus.Failed;
   101→        FailureReason = reason;
   102→        UpdatedAt = DateTime.UtcNow;
   103→    }
   104→
   105→    /// <summary>
   106→    /// Marks this payment as refunded.
   107→    /// </summary>
   108→    public void MarkAsRefunded()
   109→    {
   110→        Status = PaymentStatus.Refunded;
   111→        UpdatedAt = DateTime.UtcNow;
   112→    }
   113→
   114→    /// <summary>
   115→    /// Increments the retry counter for failed payment reattempts.
   116→    /// </summary>
   117→    public void IncrementRetryCount()
   118→    {
   119→        RetryCount++;
   120→        UpdatedAt = DateTime.UtcNow;
   121→    }
   122→
   123→    /// <summary>
   124→    /// Clears all pending domain events from this aggregate.
   125→    /// </summary>
   126→    public void ClearDomainEvents()
   127→    {
   128→        _domainEvents.Clear();
   129→    }
   130→}
   131→

