     8→/// <summary>
     9→/// Represents a platform user with authentication credentials,
    10→/// profile information, and role-based access control.
    11→/// Serves as an aggregate root for user-related operations.
    12→/// </summary>
    13→public class User : IAggregateRoot
    14→{
    15→    private readonly List<IDomainEvent> _domainEvents = new();
    16→
    17→    /// <summary>
    18→    /// Gets the unique identifier for this user.
    19→    /// </summary>
    20→    public Guid Id { get; private set; }
    21→
    22→    /// <summary>
    23→    /// Gets the timestamp when this user was created.
    24→    /// </summary>
    25→    public DateTime CreatedAt { get; private set; }
    26→
    27→    /// <summary>
    28→    /// Gets the timestamp when this user was last modified.
    29→    /// </summary>
    30→    public DateTime? UpdatedAt { get; private set; }
    31→
    32→    /// <summary>
    33→    /// Gets or sets the user's display name.
    34→    /// </summary>
    35→    public string DisplayName { get; private set; } = string.Empty;
    36→
    37→    /// <summary>
    38→    /// Gets or sets the user's validated email address.
    39→    /// </summary>
    40→    public EmailAddress Email { get; private set; } = null!;
    41→
    42→    /// <summary>
    43→    /// Gets or sets the user's optional phone number.
    44→    /// </summary>
    45→    public PhoneNumber? PhoneNumber { get; private set; }
    46→
    47→    /// <summary>
    48→    /// Gets the user's assigned role within the platform.
    49→    /// </summary>
    50→    public UserRole Role { get; private set; }
    51→
    52→    /// <summary>
    53→    /// Gets whether the user's email has been confirmed.
    54→    /// </summary>
    55→    public bool IsEmailConfirmed { get; private set; }
    56→
    57→    /// <summary>
    58→    /// Gets whether the user account is currently active.
    59→    /// </summary>
    60→    public bool IsActive { get; private set; }
    61→
    62→    /// <summary>
    63→    /// Gets the hashed password for this user.
    64→    /// Never store or log the plain-text password.
    65→    /// </summary>
    66→    public string PasswordHash { get; private set; } = string.Empty;
    67→
    68→    /// <summary>
    69→    /// Gets the collection of domain events raised by this aggregate.
    70→    /// </summary>
    71→    public IReadOnlyCollection<IDomainEvent> DomainEvents => _domainEvents.AsReadOnly();
    72→
    73→    /// <summary>
    74→    /// Creates a new User instance with the required fields.
    75→    /// Raises a UserCreatedEvent upon successful creation.
    76→    /// </summary>
    77→    public static User Create(string displayName, EmailAddress email, string passwordHash, UserRole role)
    78→    {
    79→        var user = new User
    80→        {
    81→            Id = Guid.NewGuid(),
    82→            DisplayName = displayName,
    83→            Email = email,
    84→            PasswordHash = passwordHash,
    85→            Role = role,
    86→            IsActive = true,
    87→            IsEmailConfirmed = false,
    88→            CreatedAt = DateTime.UtcNow
    89→        };
    90→
    91→        user._domainEvents.Add(new UserCreatedEvent(user.Id, email.Value));
    92→        return user;
    93→    }
    94→
    95→    /// <summary>
    96→    /// Updates the user's profile information.
    97→    /// </summary>
    98→    public void UpdateProfile(string displayName, PhoneNumber? phoneNumber)
    99→    {
   100→        DisplayName = displayName;
   101→        PhoneNumber = phoneNumber;
   102→        UpdatedAt = DateTime.UtcNow;
   103→    }
   104→
   105→    /// <summary>
   106→    /// Confirms the user's email address after verification.
   107→    /// </summary>
   108→    public void ConfirmEmail()
   109→    {
   110→        IsEmailConfirmed = true;
   111→        UpdatedAt = DateTime.UtcNow;
   112→    }
   113→
   114→    /// <summary>
   115→    /// Deactivates the user account, preventing further logins.
   116→    /// </summary>
   117→    public void Deactivate()
   118→    {
   119→        IsActive = false;
   120→        UpdatedAt = DateTime.UtcNow;
   121→    }
   122→
   123→    /// <summary>
   124→    /// Reactivates a previously deactivated user account.
   125→    /// </summary>
   126→    public void Reactivate()
   127→    {
   128→        IsActive = true;
   129→        UpdatedAt = DateTime.UtcNow;
   130→    }
   131→
   132→    /// <summary>
   133→    /// Clears all pending domain events from this aggregate.
   134→    /// </summary>
   135→    public void ClearDomainEvents()
   136→    {
   137→        _domainEvents.Clear();
   138→    }
   139→}
