     2→
     3→namespace CSharpLargeApi.Domain.ValueObjects;
     4→
     5→/// <summary>
     6→/// Represents a validated email address.
     7→/// Ensures the email conforms to a basic format on construction.
     8→/// </summary>
     9→public sealed class EmailAddress : IEquatable<EmailAddress>
    10→{
    11→    private static readonly Regex EmailPattern = new(
    12→        @"^[^@\s]+@[^@\s]+\.[^@\s]+$",
    13→        RegexOptions.Compiled | RegexOptions.IgnoreCase);
    14→
    15→    /// <summary>
    16→    /// Gets the validated email address string.
    17→    /// </summary>
    18→    public string Value { get; }
    19→
    20→    /// <summary>
    21→    /// Creates a new EmailAddress after validating the format.
    22→    /// </summary>
    23→    public EmailAddress(string value)
    24→    {
    25→        if (string.IsNullOrWhiteSpace(value))
    26→            throw new ArgumentException("Email address cannot be empty.", nameof(value));
    27→
    28→        if (!EmailPattern.IsMatch(value))
    29→            throw new ArgumentException($"'{value}' is not a valid email address.", nameof(value));
    30→
    31→        Value = value.Trim().ToLowerInvariant();
    32→    }
    33→
    34→    /// <summary>
    35→    /// Gets the domain portion of the email address.
    36→    /// </summary>
    37→    public string Domain => Value.Split('@')[1];
    38→
    39→    /// <summary>
    40→    /// Gets the local part (before the @) of the email address.
    41→    /// </summary>
    42→    public string LocalPart => Value.Split('@')[0];
    43→
    44→    /// <summary>
    45→    /// Determines whether this email equals another.
    46→    /// </summary>
    47→    public bool Equals(EmailAddress? other)
    48→    {
    49→        if (other is null) return false;
    50→        return Value == other.Value;
    51→    }
    52→
    53→    /// <inheritdoc />
    54→    public override bool Equals(object? obj) => Equals(obj as EmailAddress);
    55→
    56→    /// <inheritdoc />
    57→    public override int GetHashCode() => Value.GetHashCode();
    58→
    59→    /// <inheritdoc />
    60→    public override string ToString() => Value;
    61→}
