     5→/// <summary>
     6→/// Represents a validated phone number with country code.
     7→/// Stored in E.164 format (e.g. "+14155552671").
     8→/// </summary>
     9→public sealed class PhoneNumber : IEquatable<PhoneNumber>
    10→{
    11→    private static readonly Regex PhonePattern = new(
    12→        @"^\+[1-9]\d{6,14}$",
    13→        RegexOptions.Compiled);
    14→
    15→    /// <summary>
    16→    /// Gets the phone number in E.164 format.
    17→    /// </summary>
    18→    public string Value { get; }
    19→
    20→    /// <summary>
    21→    /// Creates a new PhoneNumber after validating the E.164 format.
    22→    /// </summary>
    23→    public PhoneNumber(string value)
    24→    {
    25→        if (string.IsNullOrWhiteSpace(value))
    26→            throw new ArgumentException("Phone number cannot be empty.", nameof(value));
    27→
    28→        var normalized = value.Replace(" ", "").Replace("-", "").Replace("(", "").Replace(")", "");
    29→
    30→        if (!PhonePattern.IsMatch(normalized))
    31→            throw new ArgumentException($"'{value}' is not a valid E.164 phone number.", nameof(value));
    32→
    33→        Value = normalized;
    34→    }
    35→
    36→    /// <summary>
    37→    /// Gets the country code portion of the phone number.
    38→    /// </summary>
    39→    public string CountryCode
    40→    {
    41→        get
    42→        {
    43→            // Simple heuristic: 1-3 digit country codes
    44→            if (Value.StartsWith("+1") && Value.Length == 12) return "+1";
    45→            return Value[..3];
    46→        }
    47→    }
    48→
    49→    /// <summary>
    50→    /// Determines whether this phone number equals another.
    51→    /// </summary>
    52→    public bool Equals(PhoneNumber? other)
    53→    {
    54→        if (other is null) return false;
    55→        return Value == other.Value;
    56→    }
    57→
    58→    /// <inheritdoc />
    59→    public override bool Equals(object? obj) => Equals(obj as PhoneNumber);
    60→
    61→    /// <inheritdoc />
    62→    public override int GetHashCode() => Value.GetHashCode();
    63→
    64→    /// <inheritdoc />
    65→    public override string ToString() => Value;
    66→}
    67→

