     1→using CSharpLargeApi.Application.Interfaces;
     2→using CSharpLargeApi.Domain.Entities;
     3→using CSharpLargeApi.Domain.Enums;
     4→using CSharpLargeApi.Domain.Exceptions;
     5→using CSharpLargeApi.Domain.Interfaces;
     6→using CSharpLargeApi.Domain.ValueObjects;
     7→using CSharpLargeApi.Infrastructure.External;
     8→
     9→namespace CSharpLargeApi.Infrastructure.Services;
    10→
    11→/// <summary>
    12→/// Implementation of the payment service that orchestrates payment processing.
    13→/// This service contains THE ProcessPayment method that is the primary target
    14→/// for caller analysis benchmarks. It coordinates between the payment gateway,
    15→/// the repository, and the notification system.
    16→/// </summary>
    17→public class PaymentService : IPaymentService
    18→{
    19→    private readonly IRepository<Payment> _paymentRepository;
    20→    private readonly StripeClient _stripeClient;
    21→    private readonly INotificationService _notificationService;
    22→
    23→    /// <summary>
    24→    /// Initializes the payment service with all required dependencies.
    25→    /// </summary>
    26→    public PaymentService(
    27→        IRepository<Payment> paymentRepository,
    28→        StripeClient stripeClient,
    29→        INotificationService notificationService)
    30→    {
    31→        _paymentRepository = paymentRepository ?? throw new ArgumentNullException(nameof(paymentRepository));
    32→        _stripeClient = stripeClient ?? throw new ArgumentNullException(nameof(stripeClient));
    33→        _notificationService = notificationService ?? throw new ArgumentNullException(nameof(notificationService));
    34→    }
    35→
    36→    /// <summary>
    37→    /// Processes a payment for the specified user and amount.
    38→    /// This is the primary entry point for all payment flows in the system.
    39→    /// Validates the request, charges via the Stripe gateway, persists the
    40→    /// transaction, and sends a confirmation notification.
    41→    ///
    42→    /// This method is called by exactly 7 non-test callers:
    43→    /// 1. PaymentController.ProcessPayment
    44→    /// 2. PaymentController.RetryPayment
    45→    /// 3. SubscriptionController.RenewSubscription
    46→    /// 4. ProcessPaymentHandler.Handle
    47→    /// 5. PaymentRetryWorker.RetryFailedPayment
    48→    /// 6. InvoiceService.SettleInvoice
    49→    /// 7. RefundService.ProcessPartialRefund
    50→    /// </summary>
    51→    public async Task<Payment> ProcessPayment(Guid userId, Money amount, string paymentMethodToken, CancellationToken cancellationToken = default)
    52→    {
    53→        if (userId == Guid.Empty)
    54→        {
    55→            throw new BusinessRuleException("ValidUserRequired", "A valid user ID is required to process a payment.");
    56→        }
    57→
    58→        if (amount.Amount <= 0)
    59→        {
    60→            throw new BusinessRuleException("PositiveAmountRequired", "Payment amount must be greater than zero.");
    61→        }
    62→
    63→        if (string.IsNullOrWhiteSpace(paymentMethodToken))
    64→        {
    65→            throw new BusinessRuleException("PaymentMethodRequired", "A payment method token is required.");
    66→        }
    67→
    68→        var payment = Payment.Create(userId, amount);
    69→
    70→        try
    71→        {
    72→            var gatewayResult = await _stripeClient.ChargeAsync(
    73→                amount.Amount,
    74→                amount.Currency,
    75→                paymentMethodToken,
    76→                cancellationToken);
    77→
    78→            if (gatewayResult.Succeeded)
    79→            {
    80→                payment.MarkAsProcessed(gatewayResult.TransactionId);
    81→
    82→                await _notificationService.SendEmailAsync(
    83→                    userId,
    84→                    "Payment Successful",
    85→                    $"Your payment of {amount} has been processed. Transaction: {gatewayResult.TransactionId}",
    86→                    cancellationToken);
    87→            }
    88→            else
    89→            {
    90→                payment.MarkAsFailed(gatewayResult.ErrorMessage ?? "Payment declined by gateway.");
    91→            }
    92→        }
    93→        catch (Exception ex)
    94→        {
    95→            payment.MarkAsFailed($"Payment processing error: {ex.Message}");
    96→        }
    97→
    98→        await _paymentRepository.AddAsync(payment, cancellationToken);
    99→
   100→        return payment;
   101→    }
   102→
   103→    /// <summary>
   104→    /// Refunds a previously completed payment in full.
   105→    /// </summary>
   106→    public async Task<Payment> RefundPayment(Guid paymentId, string reason, CancellationToken cancellationToken = default)
   107→    {
   108→        var payment = await _paymentRepository.GetByIdAsync(paymentId, cancellationToken);
   109→        if (payment is null)
   110→        {
   111→            throw new EntityNotFoundException("Payment", paymentId);
   112→        }
   113→
   114→        if (payment.Status != PaymentStatus.Completed)
   115→        {
   116→            throw new BusinessRuleException(
   117→                "CompletedPaymentRequired",
   118→                $"Only completed payments can be refunded. Current status: {payment.Status}");
   119→        }
   120→
   121→        if (string.IsNullOrWhiteSpace(payment.GatewayTransactionId))
   122→        {
   123→            throw new BusinessRuleException(
   124→                "GatewayTransactionRequired",
   125→                "Cannot refund a payment without a gateway transaction ID.");
   126→        }
   127→
   128→        var refundResult = await _stripeClient.RefundAsync(
   129→            payment.GatewayTransactionId,
   130→            payment.Amount.Amount,
   131→            cancellationToken);
   132→
   133→        if (refundResult.Succeeded)
   134→        {
   135→            payment.MarkAsRefunded();
   136→
   137→            await _notificationService.SendEmailAsync(
   138→                payment.UserId,
   139→                "Refund Processed",
   140→                $"Your refund of {payment.Amount} has been processed. Reason: {reason}",
   141→                cancellationToken);
   142→        }
   143→        else
   144→        {
   145→            throw new BusinessRuleException(
   146→                "RefundFailed",
   147→                $"Refund failed: {refundResult.ErrorMessage}");
   148→        }
   149→
   150→        await _paymentRepository.SaveChangesAsync(cancellationToken);
   151→
   152→        return payment;
   153→    }
   154→
   155→    /// <summary>
   156→    /// Validates that a payment method token is still valid.
   157→    /// </summary>
   158→    public async Task<bool> ValidatePaymentMethod(string paymentMethodToken, CancellationToken cancellationToken = default)
   159→    {
   160→        if (string.IsNullOrWhiteSpace(paymentMethodToken))
   161→        {
   162→            return false;
   163→        }
   164→
   165→        return await _stripeClient.ValidatePaymentMethodAsync(paymentMethodToken, cancellationToken);
   166→    }
   167→
   168→    /// <summary>
   169→    /// Retrieves a payment by its unique identifier.
   170→    /// </summary>
   171→    public async Task<Payment?> GetPaymentAsync(Guid paymentId, CancellationToken cancellationToken = default)
   172→    {
   173→        return await _paymentRepository.GetByIdAsync(paymentId, cancellationToken);
   174→    }
   175→
   176→    /// <summary>
   177→    /// Lists all payments for a given user with pagination.
   178→    /// </summary>
   179→    public async Task<IReadOnlyList<Payment>> GetPaymentsByUserAsync(Guid userId, int skip = 0, int take = 20, CancellationToken cancellationToken = default)
   180→    {
   181→        var allPayments = await _paymentRepository.GetAllAsync(cancellationToken);
   182→        return allPayments
   183→            .Where(p => p.UserId == userId)
   184→            .OrderByDescending(p => p.CreatedAt)
   185→            .Skip(skip)
   186→            .Take(take)
   187→            .ToList()
   188→            .AsReadOnly();
   189→    }
   190→}
