     9→/// <summary>
    10→/// Implementation of the notification service that sends notifications
    11→/// through various channels (email, push, SMS, in-app).
    12→/// </summary>
    13→public class NotificationService : INotificationService
    14→{
    15→    private readonly IRepository<Notification> _notificationRepository;
    16→    private readonly SendGridClient _emailClient;
    17→
    18→    /// <summary>
    19→    /// Initializes the notification service with required dependencies.
    20→    /// </summary>
    21→    public NotificationService(
    22→        IRepository<Notification> notificationRepository,
    23→        SendGridClient emailClient)
    24→    {
    25→        _notificationRepository = notificationRepository ?? throw new ArgumentNullException(nameof(notificationRepository));
    26→        _emailClient = emailClient ?? throw new ArgumentNullException(nameof(emailClient));
    27→    }
    28→
    29→    /// <summary>
    30→    /// Sends a notification to the specified user through the given channel.
    31→    /// </summary>
    32→    public async Task SendNotificationAsync(Guid recipientId, string subject, string body, NotificationChannel channel, CancellationToken cancellationToken = default)
    33→    {
    34→        var notification = Notification.Create(recipientId, subject, body, channel);
    35→
    36→        try
    37→        {
    38→            switch (channel)
    39→            {
    40→                case NotificationChannel.Email:
    41→                    await _emailClient.SendEmailAsync(recipientId.ToString(), subject, body, cancellationToken);
    42→                    notification.MarkAsDelivered();
    43→                    break;
    44→
    45→                case NotificationChannel.Push:
    46→                    // Push notification delivery would go through a push provider
    47→                    notification.MarkAsDelivered();
    48→                    break;
    49→
    50→                case NotificationChannel.InApp:
    51→                    // In-app notifications are just stored, delivery is implicit
    52→                    notification.MarkAsDelivered();
    53→                    break;
    54→
    55→                default:
    56→                    notification.IncrementDeliveryAttempts();
    57→                    break;
    58→            }
    59→        }
    60→        catch (Exception)
    61→        {
    62→            notification.IncrementDeliveryAttempts();
    63→        }
    64→
    65→        await _notificationRepository.AddAsync(notification, cancellationToken);
    66→    }
    67→
    68→    /// <summary>
    69→    /// Sends an email notification to the specified user.
    70→    /// </summary>
    71→    public async Task SendEmailAsync(Guid recipientId, string subject, string body, CancellationToken cancellationToken = default)
    72→    {
    73→        await SendNotificationAsync(recipientId, subject, body, NotificationChannel.Email, cancellationToken);
    74→    }
    75→
    76→    /// <summary>
    77→    /// Sends a push notification to the specified user.
    78→    /// </summary>
    79→    public async Task SendPushAsync(Guid recipientId, string subject, string body, CancellationToken cancellationToken = default)
    80→    {
    81→        await SendNotificationAsync(recipientId, subject, body, NotificationChannel.Push, cancellationToken);
    82→    }
    83→
    84→    /// <summary>
    85→    /// Retrieves the count of unread notifications for a user.
    86→    /// </summary>
    87→    public async Task<int> GetUnreadCountAsync(Guid recipientId, CancellationToken cancellationToken = default)
    88→    {
    89→        var all = await _notificationRepository.GetAllAsync(cancellationToken);
    90→        return all.Count(n => n.RecipientId == recipientId && !n.IsRead);
    91→    }
    92→
    93→    /// <summary>
    94→    /// Marks all notifications as read for the specified user.
    95→    /// </summary>
    96→    public async Task MarkAllAsReadAsync(Guid recipientId, CancellationToken cancellationToken = default)
    97→    {
    98→        var all = await _notificationRepository.GetAllAsync(cancellationToken);
    99→        var unread = all.Where(n => n.RecipientId == recipientId && !n.IsRead);
   100→
   101→        foreach (var notification in unread)
   102→        {
   103→            notification.MarkAsRead();
   104→        }
   105→
   106→        await _notificationRepository.SaveChangesAsync(cancellationToken);
   107→    }
   108→}
