     3→/// <summary>
     4→/// Represents a date range with a start and end date.
     5→/// Ensures that the start date is always before or equal to the end date.
     6→/// </summary>
     7→public sealed class DateRange : IEquatable<DateRange>
     8→{
     9→    /// <summary>
    10→    /// Gets the start date of the range (inclusive).
    11→    /// </summary>
    12→    public DateTime Start { get; }
    13→
    14→    /// <summary>
    15→    /// Gets the end date of the range (inclusive).
    16→    /// </summary>
    17→    public DateTime End { get; }
    18→
    19→    /// <summary>
    20→    /// Creates a new DateRange with the specified start and end dates.
    21→    /// </summary>
    22→    public DateRange(DateTime start, DateTime end)
    23→    {
    24→        if (end < start)
    25→            throw new ArgumentException("End date must be on or after the start date.");
    26→
    27→        Start = start;
    28→        End = end;
    29→    }
    30→
    31→    /// <summary>
    32→    /// Gets the total number of days in this range.
    33→    /// </summary>
    34→    public int TotalDays => (End - Start).Days;
    35→
    36→    /// <summary>
    37→    /// Checks whether the given date falls within this range.
    38→    /// </summary>
    39→    public bool Contains(DateTime date)
    40→    {
    41→        return date >= Start && date <= End;
    42→    }
    43→
    44→    /// <summary>
    45→    /// Checks whether this range overlaps with another range.
    46→    /// </summary>
    47→    public bool Overlaps(DateRange other)
    48→    {
    49→        return Start <= other.End && End >= other.Start;
    50→    }
    51→
    52→    /// <summary>
    53→    /// Creates a new DateRange for the next month starting from the end of this range.
    54→    /// </summary>
    55→    public DateRange NextMonth()
    56→    {
    57→        var newStart = End.AddDays(1);
    58→        var newEnd = newStart.AddMonths(1).AddDays(-1);
    59→        return new DateRange(newStart, newEnd);
    60→    }
    61→
    62→    /// <summary>
    63→    /// Determines whether this date range equals another.
    64→    /// </summary>
    65→    public bool Equals(DateRange? other)
    66→    {
    67→        if (other is null) return false;
    68→        return Start == other.Start && End == other.End;
    69→    }
    70→
    71→    /// <inheritdoc />
    72→    public override bool Equals(object? obj) => Equals(obj as DateRange);
    73→
    74→    /// <inheritdoc />
    75→    public override int GetHashCode() => HashCode.Combine(Start, End);
    76→
    77→    /// <inheritdoc />
    78→    public override string ToString() => $"{Start:yyyy-MM-dd} to {End:yyyy-MM-dd}";
    79→}
    80→

