using CSharpLargeApi.Domain.Entities;
using CSharpLargeApi.Domain.ValueObjects;

namespace CSharpLargeApi.Application.Interfaces;

/// <summary>
/// Defines the contract for payment processing operations.
/// Implementations handle gateway communication, transaction recording,
/// and post-payment workflows like notifications and invoice updates.
/// </summary>
public interface IPaymentService
{
    /// <summary>
    /// Processes a payment for the specified user and amount.
    /// This is the primary entry point for all payment flows in the system.
    /// Validates the request, charges via the gateway, persists the transaction,
    /// and sends confirmation notifications.
    /// </summary>
    Task<Payment> ProcessPayment(Guid userId, Money amount, string paymentMethodToken, CancellationToken cancellationToken = default);

    /// <summary>
    /// Refunds a previously completed payment in full.
    /// </summary>
    Task<Payment> RefundPayment(Guid paymentId, string reason, CancellationToken cancellationToken = default);

    /// <summary>
    /// Validates that a payment method token is still valid and can be charged.
    /// </summary>
    Task<bool> ValidatePaymentMethod(string paymentMethodToken, CancellationToken cancellationToken = default);

    /// <summary>
    /// Retrieves a payment by its unique identifier.
    /// </summary>
    Task<Payment?> GetPaymentAsync(Guid paymentId, CancellationToken cancellationToken = default);

    /// <summary>
    /// Lists all payments for a given user, ordered by creation date descending.
    /// </summary>
    Task<IReadOnlyList<Payment>> GetPaymentsByUserAsync(Guid userId, int skip = 0, int take = 20, CancellationToken cancellationToken = default);
}

using CSharpLargeApi.Domain.Enums;

namespace CSharpLargeApi.Application.Interfaces;

/// <summary>
/// Defines the contract for sending notifications to users.
/// Supports multiple delivery channels and tracks delivery status.
/// </summary>
public interface INotificationService
{
    /// <summary>
    /// Sends a notification to the specified user through the given channel.
    /// </summary>
    Task SendNotificationAsync(Guid recipientId, string subject, string body, NotificationChannel channel, CancellationToken cancellationToken = default);

    /// <summary>
    /// Sends an email notification to the specified user.
    /// Convenience method that delegates to SendNotificationAsync with Email channel.
    /// </summary>
    Task SendEmailAsync(Guid recipientId, string subject, string body, CancellationToken cancellationToken = default);

    /// <summary>
    /// Sends a push notification to the specified user.
    /// </summary>
    Task SendPushAsync(Guid recipientId, string subject, string body, CancellationToken cancellationToken = default);

    /// <summary>
    /// Retrieves all unread notifications for the specified user.
    /// </summary>
    Task<int> GetUnreadCountAsync(Guid recipientId, CancellationToken cancellationToken = default);

    /// <summary>
    /// Marks all notifications as read for the specified user.
    /// </summary>
    Task MarkAllAsReadAsync(Guid recipientId, CancellationToken cancellationToken = default);
}

using CSharpLargeApi.Domain.Entities;
using CSharpLargeApi.Domain.Enums;
using CSharpLargeApi.Domain.ValueObjects;

namespace CSharpLargeApi.Application.Interfaces;

/// <summary>
/// Defines the contract for user management operations.
/// Handles creation, updates, authentication support, and profile management.
/// </summary>
public interface IUserService
{
    /// <summary>
    /// Creates a new user account with the given details.
    /// </summary>
    Task<User> CreateUserAsync(string displayName, EmailAddress email, string password, UserRole role, CancellationToken cancellationToken = default);

    /// <summary>
    /// Retrieves a user by their unique identifier.
    /// </summary>
    Task<User?> GetUserAsync(Guid userId, CancellationToken cancellationToken = default);

    /// <summary>
    /// Retrieves a user by their email address.
    /// </summary>
    Task<User?> GetUserByEmailAsync(string email, CancellationToken cancellationToken = default);

    /// <summary>
    /// Updates a user's profile information.
    /// </summary>
    Task<User> UpdateUserAsync(Guid userId, string displayName, PhoneNumber? phoneNumber, CancellationToken cancellationToken = default);

    /// <summary>
    /// Deactivates a user account.
    /// </summary>
    Task DeactivateUserAsync(Guid userId, CancellationToken cancellationToken = default);

    /// <summary>
    /// Lists users with pagination support.
    /// </summary>
    Task<IReadOnlyList<User>> ListUsersAsync(int skip = 0, int take = 20, CancellationToken cancellationToken = default);
}

